}

@using sv_3ade00b79acf4577859dbc8782f8ddd9.Services

<div class="channel-list">
    <div class="channel-list-header">
        <h3>Channels</h3>
    </div>
    <nav class="channel-nav">
        @foreach (var channel in Channels)
        {
            <button class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
                    @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name-row">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
                @if (!string.IsNullOrWhiteSpace(channel.Description))
                {
                    <span class="channel-desc">@Truncate(channel.Description, 40)</span>
                }
            </button>
        }
    </nav>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string Truncate(string text, int max) =>
        text.Length <= max ? text : text[..max] + "…";
}

.channel-list {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #2b2d31;
    color: #b5bac1;
}

.channel-list-header {
    padding: 16px 16px 12px;
    border-bottom: 1px solid #1e1f22;
}

.channel-list-header h3 {
    margin: 0;
    font-size: 1rem;
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.channel-nav {
    flex: 1;
    overflow-y: auto;
    padding: 8px;
}

.channel-item {
    display: block;
    width: 100%;
    text-align: left;
    padding: 8px 12px;
    margin-bottom: 2px;
    background: none;
    border: none;
    border-radius: 6px;
    color: #8e9297;
    cursor: pointer;
    transition: background 0.1s, color 0.1s;
}

.channel-item:hover {
    background: #35373c;
    color: #dcddde;
}

.channel-item.active {
    background: #404249;
    color: #fff;
}

.channel-name-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
}

.unread-badge {
    background: #f23f42;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-desc {
    display: block;
    font-size: 0.75rem;
    color: #6d6f78;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

@using sv_3ade00b79acf4577859dbc8782f8ddd9.Services

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-quote">
            <span class="quote-author">@RootMessage.Author</span>
            <p class="quote-content">@RootMessage.Content</p>
        </div>

        <div class="thread-replies">
            @if (Replies.Count == 0)
            {
                <p class="no-replies">No replies yet. Start the conversation!</p>
            }
            else
            {
                @foreach (var reply in Replies)
                {
