toolArgs.file_text:
.message-item {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f2f3f5;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #2e3338;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.9rem;
    color: #3a3c42;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    font-size: 0.8rem;
    border: 1px solid #e0e0e0;
    border-radius: 12px;
    background: #f0f1f3;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #dfe1e5;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    font-size: 0.8rem;
    color: #5865f2;
    background: none;
    border: none;
    cursor: pointer;
    padding: 0;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: -12px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
    z-index: 10;
}

.action-btn {
    padding: 4px 10px;
    font-size: 0.78rem;
    background: none;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    color: #555;
    white-space: nowrap;
}

.action-btn:hover {
    background: #f0f1f3;
    color: #2e3338;
}

.emoji-picker-wrapper {
    position: relative;
}

.emoji-picker {
    position: absolute;
    top: 100%;
    right: 0;
    display: flex;
    gap: 2px;
    padding: 6px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.12);
    z-index: 20;
}

.emoji-option {
    font-size: 1.2rem;
    padding: 4px 6px;
    background: none;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

.emoji-option:hover {
    background: #f0f1f3;
}

