toolArgs.file_text:
@using sv_3ade00b79acf4577859dbc8782f8ddd9.Services

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-quote">
            <span class="quote-author">@RootMessage.Author</span>
            <p class="quote-content">@RootMessage.Content</p>
        </div>

        <div class="thread-replies">
            @if (Replies.Count == 0)
            {
                <p class="no-replies">No replies yet. Start the conversation!</p>
            }
            else
            {
                @foreach (var reply in Replies)
                {
                    <MessageItem Message="reply"
                                 IsThreadRoot="false"
                                 OnReact="OnReact" />
                }
            }
        </div>

        <MessageInput Placeholder="Reply in thread..."
                      ButtonText="Reply"
                      OnSubmit="OnReply" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message? RootMessage { get; set; }
    [Parameter, EditorRequired] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #e0e0e0;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
}

.thread-header h4 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #2e3338;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #888;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background: #f0f1f3;
    color: #2e3338;
}

.thread-root-quote {
    padding: 12px 16px;
    margin: 8px 12px;
    background: #f9f9fb;
    border-left: 3px solid #5865f2;
    border-radius: 0 6px 6px 0;
}

.quote-author {
    font-weight: 700;
    font-size: 0.85rem;
    color: #2e3338;
}

.quote-content {
    margin: 4px 0 0;
    font-size: 0.85rem;
    color: #555;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.no-replies {
    text-align: center;
    color: #999;
    font-size: 0.85rem;
    padding: 24px 16px;
}

