toolArgs.file_text:
@using sv_3ade00b79acf4577859dbc8782f8ddd9.Services
@inject IJSRuntime JS

<div class="message-area">
    <div class="message-area-header">
        <h3># @ChannelName</h3>
        @if (!string.IsNullOrEmpty(ChannelDescription))
        {
            <span class="channel-description">@ChannelDescription</span>
        }
    </div>

    <div class="message-list" @ref="_messageListRef" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-more">Loading older messages…</div>
        }
        @if (HasMoreMessages && !IsLoadingMore)
        {
            <div class="load-more-hint">Scroll up to load more</div>
        }
        @foreach (var message in Messages)
        {
            var summary = ThreadSummaries.GetValueOrDefault(message.Id);
            var isThreadRoot = summary is not null || Messages.Any(m => m.ReplyToId == message.Id);

            <MessageItem Message="message"
                         IsThreadRoot="isThreadRoot"
                         ThreadSummary="summary"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")"
                  ButtonText="Send"
                  OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public string ChannelName { get; set; } = "";
    [Parameter] public string? ChannelDescription { get; set; }
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;
    private bool _shouldScrollToBottom = true;
    private bool _isFirstRender = true;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_shouldScrollToBottom)
        {
            _shouldScrollToBottom = false;
            await JS.InvokeVoidAsync("eval",
                $"document.querySelector('[data-scroll-target]')?.scrollTo(0, document.querySelector('[data-scroll-target]')?.scrollHeight)");
        }
    }

    public void ScrollToBottom() => _shouldScrollToBottom = true;

    private async Task HandleScroll()
    {
        // JS interop would be needed for precise scroll position detection.
        // For simplicity, we provide a scroll event hook; the page coordinates loading.
    }
}

