arguments.file_text:
.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
}

@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_3ade00b79acf4577859dbc8782f8ddd9.Services
@using sv_3ade00b79acf4577859dbc8782f8ddd9.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="sidebar-panel">
        <ChannelList Channels="_channels"
                     SelectedChannelId="_selectedChannelId"
                     OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-panel @(_threadOpen ? "with-thread" : "full-width")">
        @if (_selectedChannel is not null)
        {
            <MessageArea ChannelName="@_selectedChannel.Name"
                         ChannelDescription="@_selectedChannel.Description"
                         Messages="_messages"
                         ThreadSummaries="_threadSummaries"
                         HasMoreMessages="_hasMoreMessages"
                         IsLoadingMore="_isLoadingMore"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage"
                         OnLoadMore="LoadMoreMessages" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <div class="thread-panel-container">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnReply="SendThreadReply"
                         OnReact="HandleReaction" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private List<Message> _threadReplies = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private Channel? _selectedChannel;
    private int _selectedChannelId;

    private bool _threadOpen;
    private int? _threadRootMessageId;
    private Message? _threadRootMessage;

    private int _skip;
    private const int PageSize = 50;
    private bool _hasMoreMessages = true;
    private bool _isLoadingMore;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _skip = 0;
        _hasMoreMessages = true;
        _messages = [];

        CloseThread();

        if (_selectedChannel is not null)
        {
            await LoadMessages();
            await ChatService.MarkChannelReadAsync(channelId);

            // Refresh channel list to update unread counts
            _channels = await ChatService.GetChannelsAsync();
        }
    }

    private async Task LoadMessages()
    {
        var batch = await ChatService.GetMessagesAsync(_selectedChannelId, _skip, PageSize);
        _messages.InsertRange(0, batch);
        _skip += batch.Count;
        _hasMoreMessages = batch.Count == PageSize;

        await BuildThreadSummaries();
    }

    private async Task LoadMoreMessages()
    {
        if (_isLoadingMore || !_hasMoreMessages) return;

        _isLoadingMore = true;

        try
        {
            await LoadMessages();
        }
        finally
        {
            _isLoadingMore = false;
        }
    }

    private async Task BuildThreadSummaries()
    {
        _threadSummaries.Clear();

        // Find messages that have replies
        var rootIds = _messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        var replyCounts = _messages
            .Where(m => m.ReplyToId.HasValue && rootIds.Contains(m.ReplyToId.Value))
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in replyCounts)
        {
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }

        // Also try fetching thread data for messages that might have replies
        // loaded on different pages
        foreach (var msg in _messages.Where(m => m.ReplyToId is null && !_threadSummaries.ContainsKey(m.Id)))
        {
            try
            {
                var thread = await ChatService.GetThreadAsync(msg.Id);
                if (thread.Count > 1) // includes the root message itself
                {
                    var replies = thread.Where(t => t.Id != msg.Id).ToList();
                    if (replies.Count > 0)
                    {
                        _threadSummaries[msg.Id] = new ThreadSummary(
                            msg.Id,
                            replies.Count,
                            replies.Max(r => r.SentAt)
                        );
                    }
                }
            }
            catch
            {
                // Thread may not exist yet — that's fine
            }
        }
    }

    private async Task OpenThread(int messageId)
    {
        _threadRootMessageId = messageId;
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        _threadOpen = true;

        var thread = await ChatService.GetThreadAsync(messageId);
        _threadReplies = thread.Where(m => m.Id != messageId).OrderBy(m => m.SentAt).ToList();
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessageId = null;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannel is null) return;

        var message = await ChatService.SendMessageAsync(_selectedChannelId, content, null);
        _messages.Add(message);
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessageId is null) return;

        var reply = await ChatService.SendMessageAsync(
            _selectedChannelId, content, _threadRootMessageId);
        _threadReplies.Add(reply);

        // Update thread summary in main view
        _threadSummaries[_threadRootMessageId.Value] = new ThreadSummary(
            _threadRootMessageId.Value,
            _threadReplies.Count,
            reply.SentAt
        );
    }

    private async Task HandleReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);

        // Refresh messages to show updated reactions
        if (_selectedChannel is not null)
        {
            var currentSkip = _skip;
            _messages = await ChatService.GetMessagesAsync(_selectedChannelId, 0, currentSkip);
        }

        // Also refresh thread if open
        if (_threadOpen && _threadRootMessageId.HasValue)
        {
            var thread = await ChatService.GetThreadAsync(_threadRootMessageId.Value);
            _threadRootMessage = thread.FirstOrDefault(m => m.Id == _threadRootMessageId.Value);
            _threadReplies = thread.Where(m => m.Id != _threadRootMessageId.Value)
                                   .OrderBy(m => m.SentAt).ToList();
        }
    }
}

